const DESC={youtube_resilient_status:"Health check and policy report.",self_test_storage:"Run internal D1/KV storage receipt test.",self_test_router:"Run internal routing receipt test.",probe_capture_cost:"Inspect a public URL and recommend lowest-cost discovery path.",capture_url_smart:"Discover public content from a URL using cheap/feed/static methods first.",capture_youtube_transcript_smart:"Discover public YouTube transcript text using public caption metadata.",capture_youtube_transcript_auto:"Alias for capture_youtube_transcript_smart.",extract_static_metadata:"Fetch public static metadata without browser rendering.",extract_caption_tracks:"Inspect public YouTube caption metadata and timed-text.",extract_readable_article:"Extract article-like public text from static HTML.",discover_public_feeds:"Discover RSS, Atom, JSON Feed, sitemap, and podcast feeds.",inspect_rss_feed:"Inspect a public RSS, Atom, or JSON feed.",inspect_podcast_feed:"Inspect a public podcast RSS feed.",discover_podcast_transcripts:"Find transcript links exposed in public podcast feeds.",capture_feed_item:"Store one feed item or podcast episode metadata.",capture_feed_items:"Bulk ingest latest N feed items with dedupe and receipts.",capture_url_sources:"Discover public machine-readable sources near a URL.",rank_available_sources:"Classify and rank discovered public sources with a source ranking receipt.",submit_external_capture_result:"Store user-provided or authorized text.",store_capture:"Store user-provided or authorized text into D1/KV.",get_capture:"Retrieve a stored public-content record.",search_captures:"Multi-term ranked search across stored public-content records.",summarize_capture:"Summarize a stored public-content record and return receipt.",get_browser_capture_helper:"Return helper page URL for authorized manual fallback only.",probe_youtube_sources:"Alias for YouTube public caption source inspection.",capture_youtube_transcript_resilient:"Alias for public-caption transcript discovery.",submit_browser_caption_payload:"Alias for storing authorized transcript text.",import_transcript_text:"Alias for storing user-provided transcript text.",get_youtube_transcript_resilient:"Alias for get_capture.",list_youtube_transcripts_resilient:"List stored YouTube transcript records.",search_youtube_transcripts_resilient:"Alias for search_captures filtered to YouTube transcripts.",summarize_youtube_transcript_resilient:"Alias for summarize_capture.",discovery_mode_status:"Show Discovery Mode registry, shared database strategy, and current worker roles.",discovery_mesh_status:"Show the live Discovery Mesh dashboard data, workers, shared tables, and index stats.",plan_discovery_mode:"Create a sequential public-source discovery plan for a topic or URL.",run_discovery_mode:"Run a first-pass orchestrated discovery job using the current monolith tools and write job receipts.",list_discovery_jobs:"List recent Discovery Mode jobs.",get_discovery_job:"Get one Discovery Mode job and its step receipts."};
const SCHEMA={type:"object",properties:{url:{type:"string"},feed_url:{type:"string"},item_url:{type:"string"},item_index:{type:"number"},limit:{type:"number",default:10},top_k:{type:"number",default:8},query:{type:"string"},capture_id:{type:"string"},transcript_id:{type:"string"},text:{type:"string"},title:{type:"string"},language:{type:"string",default:"en"},force:{type:"boolean",default:false},store:{type:"boolean",default:true},include_text:{type:"boolean",default:true},include_common_paths:{type:"boolean",default:true},capture_type:{type:"string"},source_method:{type:"string"},metadata:{type:"object"}},required:[]};
