function rpc(id,result){return Response.json({jsonrpc:"2.0",id,result},{headers:CORS})}
function errResp(id,code,message){return Response.json({jsonrpc:"2.0",id,error:{code,message}},{headers:CORS})}
function tool(id,result){return rpc(id,{content:[{type:"text",text:JSON.stringify(result,null,2)}]})}
function nowIso(){return new Date().toISOString()}
function newId(prefix){return prefix+"_"+Date.now().toString(36)+"_"+Math.random().toString(36).slice(2,8)}
function receipt(kind,extra={}){return{receipt_id:newId("rcpt"),kind,worker:WORKER_NAME,version:VERSION,created_at:nowIso(),policy:POLICY,...extra}}
async function run(db,sql,params=[]){return db.prepare(sql).bind(...params).run()}
async function first(db,sql,params=[]){return db.prepare(sql).bind(...params).first()}
async function all(db,sql,params=[]){const r=await db.prepare(sql).bind(...params).all();return r.results||[]}
async function kvPut(kv,key,value){await kv.put(key,typeof value==="string"?value:JSON.stringify(value))}
async function kvGet(kv,key){const v=await kv.get(key);if(v===null)return null;try{return JSON.parse(v)}catch{return v}}
async function schema(env){await run(env.DB,"CREATE TABLE IF NOT EXISTS afo_captures (id TEXT PRIMARY KEY, url TEXT, normalized_url TEXT, video_id TEXT, title TEXT, capture_type TEXT, language TEXT, source_method TEXT, cost_tier TEXT, browser_used INTEGER, text_kv_key TEXT, segments_kv_key TEXT, metadata_kv_key TEXT, char_count INTEGER, chunk_count INTEGER, status TEXT, error TEXT, created_at TEXT, updated_at TEXT)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_afo_captures_url ON afo_captures(normalized_url)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_afo_captures_video ON afo_captures(video_id)");await run(env.DB,"CREATE TABLE IF NOT EXISTS youtube_transcripts_resilient (id TEXT PRIMARY KEY, video_id TEXT, url TEXT, title TEXT, language TEXT, source_method TEXT, text_kv_key TEXT, segments_kv_key TEXT, char_count INTEGER, chunk_count INTEGER, status TEXT, error TEXT, created_at TEXT, updated_at TEXT)");await run(env.DB,"CREATE TABLE IF NOT EXISTS discovery_receipts (id TEXT PRIMARY KEY, kind TEXT, subject TEXT, payload_kv_key TEXT, created_at TEXT)");await run(env.DB,"CREATE TABLE IF NOT EXISTS discovery_index (id TEXT PRIMARY KEY, url TEXT UNIQUE, title TEXT, source_type TEXT, capture_type TEXT, first_query TEXT, view_count INTEGER DEFAULT 0, download_count INTEGER DEFAULT 0, capture_count INTEGER DEFAULT 0, last_action TEXT, last_seen_at TEXT, created_at TEXT)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_discovery_index_seen ON discovery_index(last_seen_at)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_discovery_index_type ON discovery_index(source_type)");await run(env.DB,"CREATE TABLE IF NOT EXISTS discovery_jobs (id TEXT PRIMARY KEY, query TEXT, seed_url TEXT, mode TEXT, status TEXT, current_step TEXT, worker_plan_kv_key TEXT, result_kv_key TEXT, created_at TEXT, updated_at TEXT)");await run(env.DB,"CREATE TABLE IF NOT EXISTS discovery_job_steps (id TEXT PRIMARY KEY, job_id TEXT, step_order INTEGER, worker_role TEXT, tool_name TEXT, status TEXT, input_kv_key TEXT, output_kv_key TEXT, created_at TEXT, updated_at TEXT)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_discovery_jobs_updated ON discovery_jobs(updated_at)");await run(env.DB,"CREATE INDEX IF NOT EXISTS idx_discovery_steps_job ON discovery_job_steps(job_id)")}
async function saveReceipt(env,r){await schema(env);const key=`receipts/${r.receipt_id}.json`;await kvPut(env.KV,key,r);try{await run(env.DB,"INSERT OR REPLACE INTO discovery_receipts VALUES (?, ?, ?, ?, ?)",[r.receipt_id,r.kind,r.subject||null,key,r.created_at||nowIso()])}catch{}return r}
function normUrl(u){try{const x=new URL(String(u));x.hash="";return x.toString()}catch{return String(u||"").trim()}}
function absUrl(base,href){try{return new URL(href,base).toString()}catch{return href}}
function hostOf(u){try{return new URL(u).hostname.replace(/^www\./,"")}catch{return""}}
function isYouTube(u){const h=hostOf(u);return h.includes("youtube.com")||h.includes("youtu.be")}
function videoId(input){try{const u=new URL(input);if(u.hostname.includes("youtu.be"))return u.pathname.split("/").filter(Boolean)[0]||null;if(u.pathname.startsWith("/shorts/"))return u.pathname.split("/").filter(Boolean)[1]||null;return u.searchParams.get("v")}catch{const m=String(input).match(/(?:v=|youtu\.be\/|shorts\/)([A-Za-z0-9_-]{6,})/);return m?m[1]:null}}
function decodeHtml(s){return String(s||"").replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g,"$1").replace(/&amp;/g,"&").replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&apos;/g,"'").replace(/&lt;/g,"<").replace(/&gt;/g,">").trim()}
function stripTags(html){return decodeHtml(String(html).replace(/<script[\s\S]*?<\/script>/gi," ").replace(/<style[\s\S]*?<\/style>/gi," ").replace(/<noscript[\s\S]*?<\/noscript>/gi," ").replace(/<[^>]+>/g," ").replace(/&nbsp;/g," ").replace(/\s+/g," "))}
function one(xml,tag){const m=String(xml).match(new RegExp(`<${tag}(?:\\s[^>]*)?>([\\s\\S]*?)<\\/${tag}>`,`i`));return m?decodeHtml(stripTags(m[1])):null}
function attr(tag,name){const m=String(tag).match(new RegExp(`${name}=["']([^"']+)["']`,`i`));return m?decodeHtml(m[1]):null}
function meta(html,name){const n=String(name).replace(/[.*+?^${}()|[\]\\]/g,"\\$&");const m=String(html).match(new RegExp(`<meta[^>]+(?:property|name)=["']${n}["'][^>]+content=["']([^"']*)["'][^>]*>`,`i`))||String(html).match(new RegExp(`<meta[^>]+content=["']([^"']*)["'][^>]+(?:property|name)=["']${n}["'][^>]*>`,`i`));return m?decodeHtml(m[1]):null}
function titleOf(html){const og=meta(html,"og:title");if(og)return og;const m=String(html).match(/<title[^>]*>([\s\S]*?)<\/title>/i);return m?decodeHtml(stripTags(m[1])):null}
async function fetchText(url,accept="text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8"){const r=await fetch(url,{headers:{"user-agent":"Mozilla/5.0 AFO public discovery","accept-language":"en-US,en;q=0.8","accept":accept}});const text=await r.text();return{ok:r.ok,status:r.status,headers:Object.fromEntries(r.headers),text,url}}
function classifySource(src){const u=(src.url||"").toLowerCase(), t=(src.type||"").toLowerCase(), k=(src.kind||"").toLowerCase();if(k.includes("youtube")||isYouTube(src.url||""))return"youtube_caption_source";if(k.includes("sitemap")||u.endsWith("sitemap.xml")||t.includes("sitemap"))return"sitemap";if(t.includes("atom")||u.includes("atom"))return"atom_feed";if(t.includes("json")||u.includes("json"))return"json_feed";if(src.transcript_url||k.includes("transcript"))return"transcript_link";if(src.enclosure_url||k.includes("audio"))return"audio_enclosure";if(t.includes("rss")||u.includes("rss")||u.includes("feed")||k.includes("feed"))return"rss_feed";if(k.includes("article"))return"article_candidate";return"html_metadata"}
function scoreSource(s){let score=10;const type=s.source_type||classifySource(s);if(type==="transcript_link")score=98;else if(type==="podcast_feed")score=92;else if(type==="rss_feed"||type==="atom_feed"||type==="json_feed")score=88;else if(type==="youtube_caption_source")score=s.available?85:35;else if(type==="audio_enclosure")score=76;else if(type==="article_candidate")score=70;else if(type==="sitemap")score=45;else if(type==="html_metadata")score=35;if(s.has_transcript)score+=8;if(s.count)score+=Math.min(10,s.count);if(s.char_count)score+=Math.min(8,Math.floor(s.char_count/1000));return score}
function explainSource(s){const type=s.source_type||classifySource(s);if(type==="transcript_link")return"Direct public transcript link is highest-value and cheapest.";if(type==="podcast_feed")return"Podcast feed exposes episode metadata, audio enclosures, and possibly transcript links.";if(type.endsWith("feed"))return"Feed provides structured public items that can be bulk-ingested cheaply.";if(type==="youtube_caption_source")return"Public caption metadata may provide transcript text without rendering.";if(type==="article_candidate")return"Static article-like text is available without rendering.";if(type==="audio_enclosure")return"Public media enclosure is useful metadata and possible later transcription input.";return"Low-cost public metadata source."}
async function staticMetadata(args){const url=normUrl(args.url);try{const r=await fetchText(url);const html=r.text;return{ok:true,url,status:r.status,title:titleOf(html),description:meta(html,"description")||meta(html,"og:description"),site_name:meta(html,"og:site_name"),type:meta(html,"og:type"),image:meta(html,"og:image"),canonical:(html.match(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']+)["']/i)||[])[1]||null,content_type:r.headers["content-type"]||null,html_bytes:html.length,policy:POLICY}}catch(e){return{ok:false,url,error:String(e.message||e),policy:POLICY}}}
async function readableArticle(args){const url=normUrl(args.url);const r=await fetchText(url);if(!r.ok)return{ok:false,url,status:r.status,error:"Static fetch failed",policy:POLICY};let html=r.text,title=titleOf(html);let main=(html.match(/<article[\s\S]*?<\/article>/i)||html.match(/<main[\s\S]*?<\/main>/i)||[])[0]||html;let text=stripTags(main);if(text.length<250)text=stripTags(html);const out={ok:text.length>40,url,status:r.status,title,capture_type:"article",source_method:"static_html_readable",source_type:"article_candidate",cost_tier:"cheap",browser_used:false,text,char_count:text.length,policy:POLICY};if(args.store){const saved=await store(env,{url,title,capture_type:"article",source_method:"static_html_readable",text,cost_tier:"cheap",browser_used:false,metadata:{status:r.status,source_type:"article_candidate",policy:POLICY}});out.capture_id=saved.id;out.write_receipt=saved.write_receipt}return out}
function feedLinksFromHtml(html,base){const out=[];const re=/<link[^>]+>/gi;let m;while((m=re.exec(String(html)))){const tag=m[0],rel=attr(tag,"rel")||"",type=attr(tag,"type")||"",href=attr(tag,"href"),title=attr(tag,"title")||null;if(!href)continue;if(/alternate|feed/i.test(rel)||/rss|atom|json\+feed|xml/i.test(type)){const src={url:absUrl(base,href),rel,type,title,kind:"feed",source:"html_link"};src.source_type=classifySource(src);out.push(src)}}return out}
async function discoverFeeds(args){const url=normUrl(args.url),found=[];let metaResult=null;try{const r=await fetchText(url);metaResult={status:r.status,title:titleOf(r.text),content_type:r.headers["content-type"]||null};if(/xml|rss|atom|feed/i.test(metaResult.content_type||"")){found.push({url,rel:"self",type:metaResult.content_type,title:metaResult.title,kind:"feed",source:"self"})}found.push(...feedLinksFromHtml(r.text,url))}catch(e){metaResult={error:String(e.message||e)}}if(args.include_common_paths!==false){try{const root=new URL(url).origin;for(const p of ["/feed","/feed/","/rss","/rss.xml","/atom.xml","/feed.xml","/podcast.xml","/sitemap.xml"]){found.push({url:root+p,rel:"common_path",type:p.includes("sitemap")?"sitemap":"feed",title:null,kind:p.includes("sitemap")?"sitemap":"feed",source:"common_path_guess"})}}catch{}}
const dedup=[],seen=new Set();for(const f of found){if(!f.url||seen.has(f.url))continue;seen.add(f.url);f.source_type=classifySource(f);dedup.push(f)}return{ok:true,url,feeds:dedup,feed_count:dedup.length,metadata:metaResult,policy:POLICY}}
function parseFeedItems(xml,limit){const raw=String(xml);if(raw.trim().startsWith("{")){try{const j=JSON.parse(raw);const items=(j.items||[]).slice(0,limit).map((it,i)=>({index:i,title:it.title||null,url:it.url||it.external_url||null,guid:it.id||it.url||null,date:it.date_published||it.date_modified||null,summary:stripTags(it.summary||it.content_text||it.content_html||""),enclosure_url:(it.attachments&&it.attachments[0]&&it.attachments[0].url)||null,enclosure_type:(it.attachments&&it.attachments[0]&&it.attachments[0].mime_type)||null}));return{format:"json_feed",title:j.title||null,description:j.description||null,home_page_url:j.home_page_url||null,items}}catch{}}
const isAtom=/<feed[\s>]/i.test(raw),title=one(raw,"title"),description=one(raw,"description")||one(raw,"subtitle");const blocks=[...raw.matchAll(isAtom?/<entry[\s\S]*?<\/entry>/gi:/<item[\s\S]*?<\/item>/gi)].slice(0,limit).map(x=>x[0]);const items=blocks.map((b,i)=>{const enclosure=(b.match(/<enclosure[^>]+>/i)||[])[0]||null;const transcript=(b.match(/<podcast:transcript[^>]+>/i)||b.match(/<transcript[^>]+>/i)||[])[0]||null;let link=one(b,"link");if(isAtom){const atomLink=(b.match(/<link[^>]+>/i)||[])[0];if(atomLink&&attr(atomLink,"href"))link=attr(atomLink,"href")}return{index:i,title:one(b,"title"),url:link||one(b,"guid"),guid:one(b,"guid")||link||one(b,"id"),date:one(b,"pubDate")||one(b,"published")||one(b,"updated"),summary:stripTags(one(b,"description")||one(b,"summary")||one(b,"content:encoded")||""),enclosure_url:enclosure?attr(enclosure,"url"):null,enclosure_type:enclosure?attr(enclosure,"type"):null,enclosure_length:enclosure?attr(enclosure,"length"):null,duration:one(b,"itunes:duration")||one(b,"duration"),transcript_url:transcript?(attr(transcript,"url")||attr(transcript,"href")):null,transcript_type:transcript?(attr(transcript,"type")||null):null}});return{format:isAtom?"atom":"rss",title,description,home_page_url:one(raw,"link"),items}}
async function inspectFeed(args){const url=normUrl(args.url),limit=Math.min(Number(args.limit||10),100);const r=await fetchText(url,"application/rss+xml,application/atom+xml,application/feed+json,application/json,application/xml,text/xml,*/*");if(!r.ok)return{ok:false,url,status:r.status,error:"Feed fetch failed",policy:POLICY};const parsed=parseFeedItems(r.text,limit),source_type=parsed.format==="atom"?"atom_feed":parsed.format==="json_feed"?"json_feed":"rss_feed";return{ok:true,url,status:r.status,content_type:r.headers["content-type"]||null,source_type,...parsed,item_count:parsed.items.length,policy:POLICY}}
async function inspectPodcast(args){const feed=await inspectFeed(args);if(!feed.ok)return feed;const episodes=(feed.items||[]).map(it=>{const hasAudio=Boolean((it.enclosure_type||"").startsWith("audio")||/\.mp3|\.m4a|\.wav/i.test(it.enclosure_url||""));return{...it,is_podcast_episode:Boolean(it.enclosure_url||it.duration||it.transcript_url),has_audio_enclosure:hasAudio,has_transcript:Boolean(it.transcript_url),source_type:it.transcript_url?"transcript_link":hasAudio?"audio_enclosure":"feed_item"}});return{...feed,source_type:"podcast_feed",feed_type:"podcast_or_media_feed",episode_count:episodes.length,audio_episode_count:episodes.filter(e=>e.has_audio_enclosure).length,transcript_count:episodes.filter(e=>e.has_transcript).length,episodes}}
async function discoverPodcastTranscripts(args){const feed=await inspectPodcast(args);if(!feed.ok)return feed;const transcripts=(feed.episodes||[]).filter(e=>e.transcript_url).slice(0,Math.min(Number(args.limit||10),50)).map(e=>({title:e.title,episode_url:e.url,transcript_url:absUrl(args.url,e.transcript_url),transcript_type:e.transcript_type||null,date:e.date,source_type:"transcript_link"}));return{ok:true,url:normUrl(args.url),transcript_count:transcripts.length,transcripts,policy:POLICY}}
async function store(env,rec){await schema(env);const id=rec.id||newId(rec.capture_type==="youtube_transcript"?"ytr":"cap");const textKey=`captures/${id}/text.txt`,segKey=`captures/${id}/segments.json`,metaKey=`captures/${id}/metadata.json`;const text=String(rec.text||"").trim();const chunks=Math.max(1,Math.ceil(text.length/1200));const metadata={...(rec.metadata||{}),source_type:rec.source_type||rec.metadata?.source_type||classifySource(rec),policy:POLICY};await kvPut(env.KV,textKey,text);await kvPut(env.KV,segKey,rec.segments||[]);await kvPut(env.KV,metaKey,metadata);await run(env.DB,"INSERT OR REPLACE INTO afo_captures VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",[id,rec.url,normUrl(rec.url),rec.video_id||null,rec.title||null,rec.capture_type||"page_text",rec.language||"en",rec.source_method||"unknown",rec.cost_tier||"cheap",rec.browser_used?1:0,textKey,segKey,metaKey,text.length,chunks,"ready",null,nowIso(),nowIso()]);if((rec.capture_type||"")==="youtube_transcript"){try{await run(env.DB,"INSERT OR REPLACE INTO youtube_transcripts_resilient VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",[id,rec.video_id||null,rec.url,rec.title||null,rec.language||"en",rec.source_method||"unknown",textKey,segKey,text.length,chunks,"ready",null,nowIso(),nowIso()])}catch{}}
const r=await saveReceipt(env,receipt("write_capture",{subject:id,capture_id:id,url:rec.url,title:rec.title,capture_type:rec.capture_type||"page_text",source_method:rec.source_method||"unknown",source_type:metadata.source_type,char_count:text.length,chunk_count:chunks,cost_tier:rec.cost_tier||"cheap",browser_used:!!rec.browser_used}));return{id,chunk_count:chunks,write_receipt:r}}
async function captureFeedItem(env,args){const feed=await inspectFeed({url:args.feed_url,limit:Math.max(Number(args.item_index||0)+1,Number(args.limit||10)||10)});if(!feed.ok)return feed;let item=null;if(args.item_url)item=(feed.items||[]).find(x=>x.url===args.item_url||x.guid===args.item_url);if(!item)item=(feed.items||[])[Number(args.item_index||0)];if(!item)return{ok:false,error:"Feed item not found",policy:POLICY};const text=[item.title,item.date,item.summary,item.enclosure_url?`Media: ${item.enclosure_url}`:"",item.transcript_url?`Transcript: ${item.transcript_url}`:""].filter(Boolean).join("\n\n");if(args.store===false)return{ok:true,item,text,policy:POLICY};const capType=item.enclosure_url?"feed_media_item":"feed_item",sourceType=item.transcript_url?"transcript_link":item.enclosure_url?"audio_enclosure":"feed_item";const saved=await store(env,{url:item.url||item.guid||args.feed_url,title:item.title,capture_type:capType,source_method:"feed_item_metadata",source_type:sourceType,text,language:"en",cost_tier:"cheap",browser_used:false,metadata:{feed_url:args.feed_url,item,source_type:sourceType}});return{ok:true,capture_id:saved.id,item,char_count:text.length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,policy:POLICY}}
async function captureFeedItems(env,args){const limit=Math.min(Math.max(Number(args.limit||10),1),100);const feed=await inspectFeed({url:args.feed_url,limit});if(!feed.ok)return feed;const captures=[],skipped=[];for(const item of feed.items||[]){const u=item.url||item.guid||`${args.feed_url}#item-${item.index}`;const existing=await first(env.DB,"SELECT id FROM afo_captures WHERE normalized_url=? LIMIT 1",[normUrl(u)]);if(existing&&!args.force){skipped.push({url:u,capture_id:existing.id,reason:"dedupe"});continue}const res=await captureFeedItem(env,{feed_url:args.feed_url,item_url:item.url||item.guid,item_index:item.index,store:true});if(res.ok)captures.push({capture_id:res.capture_id,title:item.title,url:u,source_type:res.write_receipt?.source_type||null,char_count:res.char_count});else skipped.push({url:u,error:res.error||"capture_failed"})}
const r=await saveReceipt(env,receipt("bulk_feed_ingest",{subject:args.feed_url,feed_url:args.feed_url,requested_limit:limit,captured_count:captures.length,skipped_count:skipped.length,captures,skipped}));return{ok:true,feed_url:args.feed_url,captured_count:captures.length,skipped_count:skipped.length,captures,skipped,ingest_receipt:r,policy:POLICY}}
function parseQuery(q){return String(q||"").toLowerCase().split(/[^a-z0-9]+/).filter(t=>t.length>1)}
function scoreText(row,text,q,terms){const hay=`${row.title||""} ${row.url||""} ${text}`.toLowerCase();let score=0;const exact=String(q||"").toLowerCase().trim();if(exact&&hay.includes(exact))score+=50;for(const term of terms){if(!term)continue;let c=0,idx=hay.indexOf(term);while(idx>=0&&c<20){c++;idx=hay.indexOf(term,idx+term.length)}score+=c*(String(row.title||"").toLowerCase().includes(term)?8:3);if(String(row.url||"").toLowerCase().includes(term))score+=2}return score}
async function searchCaptures(env,args){await schema(env);const q=String(args.query||""),terms=parseQuery(q),rows=await all(env.DB,"SELECT * FROM afo_captures ORDER BY created_at DESC LIMIT 800");const scored=[];for(const row of rows){if(args.capture_type&&row.capture_type!==args.capture_type)continue;if(args.video_id&&row.video_id!==args.video_id)continue;const text=String(await kvGet(env.KV,row.text_kv_key)||"");const score=scoreText(row,text,q,terms);if(score>0){const lower=text.toLowerCase();let pos=terms.map(t=>lower.indexOf(t)).filter(x=>x>=0).sort((a,b)=>a-b)[0];if(pos==null)pos=0;scored.push({score,capture_id:row.id,transcript_id:row.capture_type==="youtube_transcript"?row.id:undefined,url:row.url,video_id:row.video_id,title:row.title,capture_type:row.capture_type,source_method:row.source_method,cost_tier:row.cost_tier,browser_used:!!row.browser_used,snippet:text.slice(Math.max(0,pos-220),Math.min(text.length,pos+650))})}}
scored.sort((a,b)=>b.score-a.score);const hits=scored.slice(0,Math.min(Number(args.top_k||8),25));const r=await saveReceipt(env,receipt("search",{subject:q,query:q,terms,hit_count:hits.length,total_scored:scored.length,mode:"weighted_multi_term_or_fallback",top_capture_ids:hits.map(h=>h.capture_id)}));return{ok:true,query:q,terms,count:hits.length,hits,search_receipt:r,policy:POLICY}}
async function getCapture(env,args){await schema(env);const id=args.capture_id||args.transcript_id;const row=await first(env.DB,"SELECT * FROM afo_captures WHERE id=?",[id]);if(!row)return{ok:false,error:"Capture not found",policy:POLICY};const out={ok:true,capture:row,policy:POLICY};if(args.include_text!==false)out.text=await kvGet(env.KV,row.text_kv_key);return out}
async function summarize(env,args){const got=await getCapture(env,{capture_id:args.capture_id||args.transcript_id,include_text:true});if(!got.ok)return got;const text=String(got.text||"");const max=Math.min(Number(args.max_chars||5000),12000);const summary=text.slice(0,Math.min(max,1200))+(text.length>1200?"...":"");const r=await saveReceipt(env,receipt("summary",{subject:got.capture.id,capture_id:got.capture.id,title:got.capture.title,capture_type:got.capture.capture_type,input_chars:text.length,summary_chars:summary.length}));return{ok:true,capture_id:got.capture.id,title:got.capture.title,capture_type:got.capture.capture_type,summary,summary_receipt:r,policy:POLICY}}
function parseJson3(j){const seg=[],parts=[];for(const ev of j.events||[]){if(!ev.segs)continue;const s=ev.segs.map(x=>x.utf8||"").join("").replace(/\s+/g," ").trim();if(!s)continue;seg.push({start_ms:ev.tStartMs||0,dur_ms:ev.dDurationMs||0,text:s});parts.push(s)}return{text:parts.join(" ").replace(/\s+/g," ").trim(),segments:seg}}
function parseVtt(v){const seg=[],parts=[];for(const b of String(v).split(/\n\s*\n/)){if(!b.includes("-->"))continue;const lines=b.split(/\r?\n/).filter(Boolean),i=lines.findIndex(x=>x.includes("-->"));const s=lines.slice(i+1).join(" ").replace(/<[^>]+>/g,"").replace(/\s+/g," ").trim();if(s){seg.push({text:s});parts.push(s)}}return{text:parts.join(" ").replace(/\s+/g," ").trim(),segments:seg}}
function parseXmlCaption(x){const clean=String(x).replace(/<text[^>]*>/g,"\n").replace(/<\/text>/g," ").replace(/<[^>]+>/g," ").replace(/&amp;/g,"&").replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&lt;/g,"<").replace(/&gt;/g,">").replace(/\s+/g," ").trim();return{text:clean,segments:clean?[{text:clean}]:[]}}
function tracks(html){const m=String(html).match(/\"captionTracks\":(\[.*?\])\s*,\s*\"audioTracks\"/);if(!m)return[];try{return JSON.parse(m[1].replace(/\\u0026/g,"&"))}catch{return[]}}
function pickTrack(list,lang){return list.find(t=>t.languageCode===lang)||list.find(t=>String(t.languageCode||"").startsWith(String(lang).split("-")[0]))||list.find(t=>t.kind==="asr")||list[0]}
function fmtUrl(base,fmt){const u=new URL(base);u.searchParams.set("fmt",fmt);return u.toString()}
async function tryCaption(track){for(const f of ["json3","vtt","srv3","ttml"]){try{const r=await fetch(fmtUrl(track.baseUrl,f));if(!r.ok)continue;if(f==="json3"){const p=parseJson3(await r.json());if(p.text)return{parsed:p,method:"caption_json3"}}else if(f==="vtt"){const p=parseVtt(await r.text());if(p.text)return{parsed:p,method:"caption_vtt"}}else{const p=parseXmlCaption(await r.text());if(p.text)return{parsed:p,method:"caption_"+f}}}catch{}}return null}
async function extractCaptionTracks(args){const id=videoId(args.url);if(!id)return{ok:false,error:"Could not extract video_id",policy:POLICY};const lang=args.language||"en",watch=`https://www.youtube.com/watch?v=${id}`;let title=null;try{const o=await fetch(`https://www.youtube.com/oembed?format=json&url=${encodeURIComponent(watch)}`);if(o.ok)title=(await o.json()).title||null}catch{}const r=await fetchText(watch);const list=tracks(r.text),mapped=list.map(t=>({languageCode:t.languageCode||null,kind:t.kind||null,name:t.name?t.name.simpleText||null:null,hasBaseUrl:!!t.baseUrl,isTranslatable:!!t.isTranslatable,source_type:"youtube_caption_source"}));if(!args.parse)return{ok:true,video_id:id,url:watch,title,watch_status:r.status,caption_track_count:mapped.length,caption_tracks:mapped,source_type:"youtube_caption_source",policy:POLICY};if(!list.length)return{ok:false,video_id:id,url:watch,title,watch_status:r.status,error:"No public captionTracks found",caption_track_count:0,caption_tracks:[],policy:POLICY};const attempt=await tryCaption(pickTrack(list,lang));if(!attempt)return{ok:false,video_id:id,url:watch,title,watch_status:r.status,error:"Caption tracks found but no text parsed",caption_track_count:mapped.length,caption_tracks:mapped,policy:POLICY};return{ok:true,video_id:id,url:watch,title,watch_status:r.status,language:lang,caption_track_count:mapped.length,caption_tracks:mapped,source_method:attempt.method,text:attempt.parsed.text,segments:attempt.parsed.segments,char_count:attempt.parsed.text.length,cost_tier:"cheap",browser_used:false,source_type:"youtube_caption_source",policy:POLICY}}
async function browserCapture(env,args){if(!env.BROWSER_CAPTURE)return{ok:false,error:"No optional browser service binding configured"};try{const r=await env.BROWSER_CAPTURE.fetch("https://browser-capture.local/capture",{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({url:args.url,language:args.language||"en"})});return await r.json()}catch(e){return{ok:false,error:String(e.message||e)}}}
async function ytSmart(env,args){await schema(env);const id=videoId(args.url);if(!id)return{ok:false,error:"Could not extract video_id",policy:POLICY};const lang=args.language||"en",watch=`https://www.youtube.com/watch?v=${id}`;if(!args.force){const ex=await first(env.DB,"SELECT id,source_method FROM afo_captures WHERE video_id=? AND language=? AND status=? AND capture_type=? ORDER BY created_at DESC LIMIT 1",[id,lang,"ready","youtube_transcript"]);if(ex)return{ok:true,cached:true,capture_id:ex.id,transcript_id:ex.id,video_id:id,source_method:ex.source_method,auto_path:"cache",policy:POLICY}}
const direct=await extractCaptionTracks({url:watch,language:lang,parse:true});if(direct.ok&&direct.text){const saved=await store(env,{url:watch,video_id:id,title:direct.title,language:lang,capture_type:"youtube_transcript",source_method:direct.source_method,source_type:"youtube_caption_source",text:direct.text,segments:direct.segments,cost_tier:"cheap",browser_used:false,metadata:{watch_status:direct.watch_status,caption_track_count:direct.caption_track_count}});return{ok:true,auto_path:"static_caption",capture_id:saved.id,transcript_id:saved.id,video_id:id,title:direct.title,source_method:direct.source_method,char_count:direct.text.length,chunk_count:saved.chunk_count,cost_tier:"cheap",browser_used:false,write_receipt:saved.write_receipt,policy:POLICY}}
const br=await browserCapture(env,{url:watch,language:lang});if(br.ok&&br.text){const saved=await store(env,{url:watch,video_id:id,title:br.title,language:lang,capture_type:"youtube_transcript",source_method:br.source_method||"optional_browser_service",text:br.text,segments:br.segments||[],cost_tier:"browser",browser_used:true,metadata:{direct_error:direct.error||null}});return{ok:true,auto_path:"optional_browser_service",capture_id:saved.id,transcript_id:saved.id,video_id:id,title:br.title,char_count:br.text.length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,policy:POLICY}}
return{ok:false,video_id:id,auto_path:"public_paths_failed",recommended_next:"submit_external_capture_result",direct_error:direct.error||null,browser_error:br.error||null,cost_tier:"external_or_user_supplied",browser_binding:Boolean(env.BROWSER_CAPTURE),policy:POLICY}}
async function captureSources(args){const url=normUrl(args.url);const [metadata,feeds]=await Promise.all([staticMetadata({url}),discoverFeeds({url,include_common_paths:true})]);let caption=null;if(isYouTube(url))caption=await extractCaptionTracks({url,language:args.language||"en",parse:false});let article=null;try{article=await readableArticle({url,store:false})}catch(e){article={ok:false,error:String(e.message||e)}}const sources=[];if(metadata.ok)sources.push({kind:"metadata",source_type:"html_metadata",available:true,cost_tier:"cheap",title:metadata.title,details:metadata});for(const f of feeds.feeds||[])sources.push({...f,kind:"feed",available:true,cost_tier:"cheap",source_type:f.source_type||classifySource(f)});if(caption)sources.push({kind:"youtube_captions",source_type:"youtube_caption_source",available:Boolean(caption.caption_track_count),cost_tier:"cheap",count:caption.caption_track_count,details:caption});if(article&&article.ok)sources.push({kind:"readable_article",source_type:"article_candidate",available:true,cost_tier:"cheap",char_count:article.char_count,title:article.title});return{ok:true,url,sources_found:sources.length,sources,policy:POLICY}}
async function rankSources(env,args){const src=await captureSources(args);const ranked=(src.sources||[]).map(s=>{const source_type=s.source_type||classifySource(s);const score=scoreSource({...s,source_type});return{...s,source_type,score,why_selected:explainSource({...s,source_type})}}).sort((a,b)=>b.score-a.score);const r=await saveReceipt(env,receipt("source_ranking",{subject:normUrl(args.url),url:normUrl(args.url),source_count:ranked.length,best_source_type:ranked[0]?.source_type||null,recommended_path:ranked[0]?.kind||"external_or_user_supplied",ranked_sources:ranked.slice(0,10).map(x=>({source_type:x.source_type,score:x.score,url:x.url||x.details?.url||null,why_selected:x.why_selected}))}));return{ok:true,url:normUrl(args.url),best_source:ranked[0]||null,ranked_sources:ranked,recommended_path:ranked[0]?ranked[0].kind:"external_or_user_supplied",ranking_receipt:r,policy:POLICY}}
async function probeCost(env,args){const ranked=await rankSources(env,args);const browser=!ranked.best_source&&Boolean(env.BROWSER_CAPTURE);return{ok:true,url:normUrl(args.url),recommended_path:browser?"optional_browser_service":ranked.recommended_path,browser_required:browser,estimated_cost_tier:browser?"browser":"cheap",confidence:ranked.best_source?0.8:0.42,reason:ranked.best_source?`Best public source: ${ranked.best_source.source_type}`:"No strong public source found in static discovery.",ranking_receipt:ranked.ranking_receipt,ranked_sources:ranked.ranked_sources.slice(0,8),policy:POLICY}}
async function captureUrlSmart(env,args){await schema(env);const url=normUrl(args.url);if(isYouTube(url))return ytSmart(env,args);const existing=!args.force?await first(env.DB,"SELECT id,source_method FROM afo_captures WHERE normalized_url=? AND status=? ORDER BY created_at DESC LIMIT 1",[url,"ready"]):null;if(existing)return{ok:true,cached:true,capture_id:existing.id,source_method:existing.source_method,auto_path:"cache",policy:POLICY};const ranked=await rankSources(env,args),best=ranked.best_source;if(best&&(best.source_type||"").includes("feed"))return{ok:true,auto_path:"feed_discovery",recommended_next:"inspect_rss_feed",best_source:best,ranking_receipt:ranked.ranking_receipt,policy:POLICY};let art;try{art=await readableArticle({url,store:false})}catch(e){art={ok:false,error:String(e.message||e)}}if(art.ok&&art.text&&art.text.length>100){const saved=await store(env,{url,title:art.title,capture_type:"article",source_method:"static_html_readable",source_type:"article_candidate",text:art.text,cost_tier:"cheap",browser_used:false,metadata:{status:art.status}});return{ok:true,auto_path:"static_readable_article",capture_id:saved.id,title:art.title,char_count:art.text.length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,ranking_receipt:ranked.ranking_receipt,policy:POLICY}}
const br=await browserCapture(env,args);return{ok:false,auto_path:"public_paths_failed",ranking_receipt:ranked.ranking_receipt,static_error:art.error||null,browser_error:br.error||null,recommended_next:"submit_external_capture_result",policy:POLICY}}
async function listYT(env,args){await schema(env);let sql="SELECT id AS transcript_id,id AS capture_id,video_id,url,title,language,source_method,char_count,chunk_count,status,created_at,updated_at FROM afo_captures WHERE capture_type='youtube_transcript'";const p=[];if(args.video_id){sql+=" AND video_id=?";p.push(args.video_id)}if(args.language){sql+=" AND language=?";p.push(args.language)}sql+=" ORDER BY created_at DESC LIMIT ?";p.push(Math.min(Number(args.limit||20),100));const rows=await all(env.DB,sql,p);return{ok:true,count:rows.length,transcripts:rows,policy:POLICY}}
async function selfTestStorage(env){const text="AFO Smart Public Content Discovery MCP internal storage self-test fixture. This fixed text verifies D1 and KV storage, receipts, and search without external fetches.";const saved=await store(env,{id:"selftest_storage_v043",url:"urn:afo:self-test:storage",title:"AFO Storage Self Test v0.4.3",capture_type:"self_test",language:"en",source_method:"internal_fixture",source_type:"internal_fixture",text,cost_tier:"internal",browser_used:false,metadata:{self_test:true,version:VERSION}});const got=await getCapture(env,{capture_id:saved.id,include_text:true});return{ok:got.ok,capture_id:saved.id,stored_text_matches:got.text===text,char_count:text.length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,policy:POLICY}}
