async function helperInfo(args,origin){return{ok:true,worker:WORKER_NAME,version:VERSION,helper_url:(origin||"https://afo-youtube-transcript-resilient-mcp.jaredtechfit.workers.dev")+"/helper",for_url:args.url||null,note:"Preferred tools: capture_url_sources, rank_available_sources, discover_public_feeds, capture_feed_items.",policy:POLICY}}
async function handle(name,args,env,ctx,origin){switch(name){case"youtube_resilient_status":return{ok:true,product:PRODUCT_NAME,worker:WORKER_NAME,version:VERSION,policy:POLICY,browser_capture_binding:Boolean(env.BROWSER_CAPTURE),capabilities:["public_content_routing","feed_discovery","bulk_feed_ingest","source_type_classifier","source_ranking_receipts","weighted_multi_term_search","write_search_summary_receipts","podcast_feed_inspection","transcript_link_discovery","authorized_storage"],recommended_tools:["capture_url_sources","rank_available_sources","discover_public_feeds","inspect_rss_feed","inspect_podcast_feed","capture_feed_items","search_captures"]};case"discovery_mode_status":return discoveryModeStatus();case"discovery_mesh_status":return discoveryMeshStatus(env);case"plan_discovery_mode":return planDiscoveryMode(args);case"run_discovery_mode":return runDiscoveryMode(env,args,ctx,origin);case"list_discovery_jobs":return listDiscoveryJobs(env,args);case"get_discovery_job":return getDiscoveryJob(env,args);case"self_test_storage":return selfTestStorage(env);case"self_test_router":return selfTestRouter(env);case"discover_public_feeds":if(!args.url)throw new Error("url required");return discoverFeeds(args);case"inspect_rss_feed":if(!args.url)throw new Error("url required");return inspectFeed(args);case"inspect_podcast_feed":if(!args.url)throw new Error("url required");return inspectPodcast(args);case"discover_podcast_transcripts":if(!args.url)throw new Error("url required");return discoverPodcastTranscripts(args);case"capture_feed_item":if(!args.feed_url)throw new Error("feed_url required");return captureFeedItem(env,args);case"capture_feed_items":if(!args.feed_url)throw new Error("feed_url required");return captureFeedItems(env,args);case"capture_url_sources":if(!args.url)throw new Error("url required");return captureSources(args);case"rank_available_sources":if(!args.url)throw new Error("url required");return rankSources(env,args);case"probe_capture_cost":if(!args.url)throw new Error("url required");return probeCost(env,args);case"capture_url_smart":if(!args.url)throw new Error("url required");return captureUrlSmart(env,args);case"capture_youtube_transcript_smart":case"capture_youtube_transcript_auto":if(!args.url)throw new Error("url required");return ytSmart(env,args);case"extract_static_metadata":if(!args.url)throw new Error("url required");return staticMetadata(args);case"extract_caption_tracks":if(!args.url)throw new Error("url required");return extractCaptionTracks(args);case"extract_readable_article":if(!args.url)throw new Error("url required");return readableArticle({...args});case"submit_external_capture_result":if(!args.url||!args.text)throw new Error("url and text required");return (async()=>{const saved=await store(env,{url:args.url,video_id:videoId(args.url),title:args.title,capture_type:isYouTube(args.url)?"youtube_transcript":"page_text",source_method:args.source_method||"external_capture",language:args.language||"en",text:args.text,segments:args.segments||[],cost_tier:"external",browser_used:false,metadata:{submitted:true}});return{ok:true,capture_id:saved.id,transcript_id:isYouTube(args.url)?saved.id:undefined,char_count:String(args.text).length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,policy:POLICY}})();case"store_capture":if(!args.url||!args.text)throw new Error("url and text required");return (async()=>{const saved=await store(env,{url:args.url,video_id:videoId(args.url),title:args.title,capture_type:args.capture_type||"page_text",source_method:args.source_method||"manual_store",language:args.language||"en",text:args.text,cost_tier:"manual",browser_used:false,metadata:args.metadata||{}});return{ok:true,capture_id:saved.id,char_count:String(args.text).length,chunk_count:saved.chunk_count,write_receipt:saved.write_receipt,policy:POLICY}})();case"get_capture":return getCapture(env,args);case"search_captures":if(!args.query)throw new Error("query required");return searchCaptures(env,args);case"summarize_capture":return summarize(env,args);case"get_browser_capture_helper":return helperInfo(args,origin);case"probe_youtube_sources":return extractCaptionTracks({...args,parse:false});case"capture_youtube_transcript_resilient":return ytSmart(env,{...args,force:true});case"submit_browser_caption_payload":return handle("submit_external_capture_result",{...args,text:String(args.text||args.payload||"").trim(),source_method:"browser_payload"},env,ctx,origin);case"import_transcript_text":return handle("submit_external_capture_result",{...args,source_method:"manual_import"},env,ctx,origin);case"get_youtube_transcript_resilient":return getCapture(env,{capture_id:args.transcript_id,include_text:args.include_text});case"list_youtube_transcripts_resilient":return listYT(env,args);case"search_youtube_transcripts_resilient":return searchCaptures(env,{...args,capture_type:"youtube_transcript"});case"summarize_youtube_transcript_resilient":return summarize(env,{capture_id:args.transcript_id,max_chars:args.max_chars});default:throw new Error("Unknown tool: "+name)}}
function escHtml(s){return String(s||"").replace(/[&<>\"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]))}
async function upsertIndexItem(env,item,query,action="view"){await schema(env);const url=item.url||item.episode_url||item.transcript_url||item.details?.url||item.capture_id||item.source_type||"unknown";const title=item.title||item.source_type||item.capture_id||url;const source_type=item.source_type||item.capture_type||item.kind||"unknown";const capture_type=item.capture_type||null;const existing=await first(env.DB,"SELECT id,view_count,download_count,capture_count FROM discovery_index WHERE url=?",[url]);const id=existing?.id||newId("idx");const viewInc=action==="view"?1:0,downloadInc=action==="download"?1:0,captureInc=action==="capture"?1:0;if(existing){await run(env.DB,"UPDATE discovery_index SET title=COALESCE(?,title), source_type=COALESCE(?,source_type), capture_type=COALESCE(?,capture_type), view_count=view_count+?, download_count=download_count+?, capture_count=capture_count+?, last_action=?, last_seen_at=? WHERE url=?",[title,source_type,capture_type,viewInc,downloadInc,captureInc,action,nowIso(),url])}else{await run(env.DB,"INSERT OR REPLACE INTO discovery_index VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",[id,url,title,source_type,capture_type,query||null,viewInc,downloadInc,captureInc,action,nowIso(),nowIso()])}return{id,url,title,source_type,capture_type,action}}
async function indexResultRows(env,result,query,action="view"){const rows=compactRows(result);const indexed=[];for(const row of rows.slice(0,50)){try{indexed.push(await upsertIndexItem(env,row,query,action))}catch(e){}}return indexed}
function discoveryWorkerRegistry(){return[{role:"orchestrator",worker:"current",tool:"run_discovery_mode",status:"active",writes:["discovery_jobs","discovery_job_steps","discovery_index","discovery_receipts"]},{role:"source_ranker",worker:"current",tool:"rank_available_sources",status:"active",writes:["discovery_receipts","discovery_index"]},{role:"feed_discoverer",worker:"current",tool:"discover_public_feeds",status:"active",writes:["discovery_index"]},{role:"podcast_inspector",worker:"current",tool:"inspect_podcast_feed",status:"active",writes:["afo_captures","discovery_index"]},{role:"bulk_feed_ingester",worker:"current",tool:"capture_feed_items",status:"active",writes:["afo_captures","discovery_index","discovery_receipts"]},{role:"capture_searcher",worker:"current",tool:"search_captures",status:"active",writes:["discovery_receipts"]},{role:"article_metadata_worker",worker:"future",tool:"extract_readable_article",status:"planned",writes:["afo_captures","discovery_index"]},{role:"youtube_metadata_worker",worker:"future",tool:"extract_caption_tracks",status:"planned",writes:["afo_captures","discovery_index"]},{role:"sitemap_worker",worker:"future",tool:"inspect_sitemap",status:"planned",writes:["discovery_index"]},{role:"report_export_worker",worker:"future",tool:"export_discovery_report",status:"planned",writes:["discovery_receipts"]}]}
function discoveryModeStatus(){return{ok:true,product:"AFO Public Discovery Mode",version:VERSION,pattern:"orchestrator_plus_specialized_workers_shared_database",shared_tables:["discovery_jobs","discovery_job_steps","discovery_index","discovery_receipts","afo_captures"],registry:discoveryWorkerRegistry(),next_split_candidates:["feed_discoverer","podcast_inspector","sitemap_worker","youtube_metadata_worker","article_metadata_worker"],policy:POLICY}}
function planDiscoveryMode(args={}){const query=args.query||args.q||"";const seed_url=args.url||args.seed_url||"";const isUrl=/^https?:\/\//i.test(seed_url||query);const plan=[{order:1,worker_role:"orchestrator",tool_name:"plan_discovery_mode",reason:"Create a deterministic public-source discovery route."},{order:2,worker_role:"source_ranker",tool_name:"rank_available_sources",reason:"Classify available public source types and choose cheap first steps."},{order:3,worker_role:"feed_discoverer",tool_name:"discover_public_feeds",reason:"Find RSS, Atom, podcast feeds, JSON feeds, and sitemap candidates."},{order:4,worker_role:"podcast_inspector",tool_name:"inspect_podcast_feed",reason:"If a feed exists, inspect episode/item metadata and transcript links."},{order:5,worker_role:"bulk_feed_ingester",tool_name:"capture_feed_items",reason:"Ingest a small deduped batch into shared D1/KV."},{order:6,worker_role:"capture_searcher",tool_name:"search_captures",reason:"Search the accumulated index and return ranked stored results."}];return{ok:true,query,seed_url,mode:isUrl?"url_seed":"topic_seed",plan,shared_database_strategy:"Every worker writes small normalized records plus receipts into the same D1/KV-backed discovery layer.",policy:POLICY}}
async function createDiscoveryJob(env,args,plan){await schema(env);const id=newId("job");const planKey=`jobs/${id}/plan.json`;const resultKey=`jobs/${id}/result.json`;await kvPut(env.KV,planKey,plan);await kvPut(env.KV,resultKey,{status:"created"});await run(env.DB,"INSERT OR REPLACE INTO discovery_jobs VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",[id,args.query||args.q||null,args.url||args.seed_url||null,plan.mode,"running","created",planKey,resultKey,nowIso(),nowIso()]);return{id,planKey,resultKey}}
async function saveJobStep(env,job_id,order,role,tool,status,input,output){const id=newId("step");const inKey=`jobs/${job_id}/steps/${order}-input.json`;const outKey=`jobs/${job_id}/steps/${order}-output.json`;await kvPut(env.KV,inKey,input||{});await kvPut(env.KV,outKey,output||{});await run(env.DB,"INSERT OR REPLACE INTO discovery_job_steps VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",[id,job_id,order,role,tool,status,inKey,outKey,nowIso(),nowIso()]);await run(env.DB,"UPDATE discovery_jobs SET current_step=?, updated_at=? WHERE id=?",[role,nowIso(),job_id]);return{id,job_id,order,role,tool,status}}
async function runDiscoveryMode(env,args,ctx,origin){const plan=planDiscoveryMode(args);const job=await createDiscoveryJob(env,args,plan);const query=args.query||args.q||"";const seed=args.url||args.seed_url||query;const outputs=[];await saveJobStep(env,job.id,1,"orchestrator","plan_discovery_mode","ok",args,plan);outputs.push({step:1,role:"orchestrator",result:plan});if(/^https?:\/\//i.test(seed||"")){const ranked=await rankSources(env,{url:seed,language:args.language||"en"});await indexResultRows(env,ranked,seed,"view");await saveJobStep(env,job.id,2,"source_ranker","rank_available_sources","ok",{url:seed},ranked);outputs.push({step:2,role:"source_ranker",result:ranked});const feeds=await discoverFeeds({url:seed,include_common_paths:true});await indexResultRows(env,feeds,seed,"view");await saveJobStep(env,job.id,3,"feed_discoverer","discover_public_feeds","ok",{url:seed},feeds);outputs.push({step:3,role:"feed_discoverer",result:feeds});const firstFeed=(feeds.feeds||[]).find(f=>(f.source_type||"").includes("feed"));if(firstFeed){const pod=await inspectPodcast({url:firstFeed.url,limit:Number(args.limit||5)});await indexResultRows(env,pod,seed,"view");await saveJobStep(env,job.id,4,"podcast_inspector","inspect_podcast_feed","ok",{url:firstFeed.url},pod);outputs.push({step:4,role:"podcast_inspector",result:pod});const ing=await captureFeedItems(env,{feed_url:firstFeed.url,limit:Number(args.ingest_limit||3),force:false});await indexResultRows(env,ing,seed,"capture");await saveJobStep(env,job.id,5,"bulk_feed_ingester","capture_feed_items","ok",{feed_url:firstFeed.url},ing);outputs.push({step:5,role:"bulk_feed_ingester",result:ing})}}const search=await searchCaptures(env,{query:query||seed,top_k:Number(args.top_k||10)});await saveJobStep(env,job.id,6,"capture_searcher","search_captures","ok",{query:query||seed},search);outputs.push({step:6,role:"capture_searcher",result:search});const result={ok:true,job_id:job.id,status:"complete",query,seed_url:seed,steps:outputs.map(o=>({step:o.step,role:o.role,ok:o.result?.ok!==false,count:o.result?.count||o.result?.item_count||o.result?.captured_count||o.result?.sources_found||0})),final_results:search.hits||[],policy:POLICY};await kvPut(env.KV,job.resultKey,result);await run(env.DB,"UPDATE discovery_jobs SET status=?, current_step=?, updated_at=? WHERE id=?",["complete","complete",nowIso(),job.id]);return result}
async function listDiscoveryJobs(env,args={}){await schema(env);const rows=await all(env.DB,"SELECT * FROM discovery_jobs ORDER BY updated_at DESC LIMIT ?",[Math.min(Number(args.limit||25),100)]);return{ok:true,count:rows.length,jobs:rows,policy:POLICY}}
async function getDiscoveryJob(env,args={}){await schema(env);const id=args.job_id||args.id;const job=await first(env.DB,"SELECT * FROM discovery_jobs WHERE id=?",[id]);if(!job)return{ok:false,error:"job not found",policy:POLICY};const steps=await all(env.DB,"SELECT * FROM discovery_job_steps WHERE job_id=? ORDER BY step_order ASC",[id]);const result=await kvGet(env.KV,job.result_kv_key);return{ok:true,job,steps,result,policy:POLICY}}
function discoveryMeshWorkers(){return[{name:"Orchestrator",script:"afo-youtube-transcript-resilient-mcp",role:"orchestrator",status:"live",url:"https://afo-youtube-transcript-resilient-mcp.jaredtechfit.workers.dev",tools:["run_discovery_mode","search_captures"]},{name:"Feed Discoverer",script:"afo-feed-discoverer-worker",role:"feed_discoverer",status:"live",url:"https://afo-feed-discoverer-worker.jaredtechfit.workers.dev",tools:["discover_public_feeds","run_feed_discovery_job"]},{name:"Podcast Inspector",script:"afo-podcast-inspector-worker",role:"podcast_inspector",status:"live",url:"https://afo-podcast-inspector-worker.jaredtechfit.workers.dev",tools:["inspect_podcast_feed","run_podcast_inspection_job"]},{name:"Article Metadata",script:"afo-article-metadata-worker",role:"article_metadata_worker",status:"live",url:"https://afo-article-metadata-worker.jaredtechfit.workers.dev",tools:["extract_article_metadata","run_article_metadata_job"]},{name:"Sitemap Discovery",script:"afo-sitemap-discovery-worker",role:"sitemap_worker",status:"live",url:"https://afo-sitemap-discovery-worker.jaredtechfit.workers.dev",tools:["inspect_sitemap","run_sitemap_discovery_job"]}]}
async function meshStats(env){await schema(env);const index_count=(await first(env.DB,"SELECT COUNT(*) AS n FROM discovery_index",[]))?.n||0;const job_count=(await first(env.DB,"SELECT COUNT(*) AS n FROM discovery_jobs",[]))?.n||0;const receipt_count=(await first(env.DB,"SELECT COUNT(*) AS n FROM discovery_receipts",[]))?.n||0;const capture_count=(await first(env.DB,"SELECT COUNT(*) AS n FROM afo_captures",[]))?.n||0;const by_type=await all(env.DB,"SELECT source_type, COUNT(*) AS n FROM discovery_index GROUP BY source_type ORDER BY n DESC LIMIT 12",[]);const recent=await all(env.DB,"SELECT url,title,source_type,capture_type,last_action,last_seen_at FROM discovery_index ORDER BY last_seen_at DESC LIMIT 20",[]);return{index_count,job_count,receipt_count,capture_count,by_type,recent}}
async function discoveryMeshStatus(env){return{ok:true,product:"AFO Discovery Mesh",version:VERSION,description:"Specialized public-content discovery workers connected to one shared D1/KV discovery layer.",workers:discoveryMeshWorkers(),shared_database:{tables:["discovery_index","discovery_jobs","discovery_job_steps","discovery_receipts","afo_captures"],stats:await meshStats(env)},policy:POLICY}}
function renderMeshDashboard(data){const s=data.shared_database?.stats||{};const workers=(data.workers||[]).map(w=>`<div class="card"><h3>${escHtml(w.name)}</h3><div class="small">${escHtml(w.role)} · ${escHtml(w.status)} · ${escHtml(w.script)}</div><p>${escHtml((w.tools||[]).join(" · "))}</p><div class="actions"><a class="btn" href="${escHtml(w.url)}/health" target="_blank">Health</a><a class="btn" href="${escHtml(w.url)}/console" target="_blank">Console</a></div></div>`).join("");const types=(s.by_type||[]).map(x=>`<div class="card"><b>${escHtml(x.source_type||"unknown")}</b><div class="small">${escHtml(x.n)} indexed rows</div></div>`).join("");const recent=(s.recent||[]).map(x=>`<div class="card"><a href="${escHtml(x.url)}" target="_blank">${escHtml(x.title||x.url)}</a><div class="small">${escHtml([x.source_type,x.capture_type,x.last_action,x.last_seen_at].filter(Boolean).join(" · "))}</div></div>`).join("");return `<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>AFO Discovery Mesh</title><style>body{font-family:system-ui;margin:0;background:#f8fafc;color:#0f172a}.wrap{max-width:1180px;margin:auto;padding:24px}.hero{background:#0f172a;color:white;border-radius:24px;padding:28px}.hero p{color:#cbd5e1}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:14px;margin-top:16px}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin:16px 0}.stat,.card{background:white;border:1px solid #e2e8f0;border-radius:16px;padding:14px}.stat b{font-size:30px}.small{font-size:12px;color:#64748b}.actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}.btn{display:inline-block;background:#0284c7;color:white;text-decoration:none;border-radius:10px;padding:10px 12px;font-weight:800}.panel{margin-top:18px}@media(max-width:850px){.grid,.stats{grid-template-columns:1fr}.btn{width:100%;box-sizing:border-box;text-align:center}}</style></head><body><div class="wrap"><section class="hero"><h1>AFO Discovery Mesh Dashboard</h1><p>Specialized public-content discovery workers connected to one shared database.</p><div class="actions"><a class="btn" href="/console">Main Console</a><a class="btn" href="/discovery">Discovery Mode</a><a class="btn" href="/feed">Discovery Feed</a><a class="btn" href="/mesh.json">Mesh JSON</a></div></section><div class="stats"><div class="stat"><b>${escHtml(s.index_count||0)}</b><div>Indexed rows</div></div><div class="stat"><b>${escHtml(s.job_count||0)}</b><div>Discovery jobs</div></div><div class="stat"><b>${escHtml(s.receipt_count||0)}</b><div>Receipts</div></div><div class="stat"><b>${escHtml(s.capture_count||0)}</b><div>Captures</div></div></div><section class="panel"><h2>Live Workers</h2><div class="grid">${workers}</div></section><section class="panel"><h2>Index by Source Type</h2><div class="grid">${types||'<div class="card">No indexed source types yet.</div>'}</div></section><section class="panel"><h2>Recent Indexed Content</h2><div class="grid">${recent||'<div class="card">No recent rows yet.</div>'}</div></section></div></body></html>`}
function renderDiscoveryModePage(result){return renderResultPage("Discovery Mode",result||discoveryModeStatus())}
async function getDiscoveryFeed(env,args={}){await schema(env);const limit=Math.min(Number(args.limit||50),200);const rows=await all(env.DB,"SELECT * FROM discovery_index ORDER BY last_seen_at DESC LIMIT ?",[limit]);return{ok:true,title:"AFO Public Discovery Feed",count:rows.length,items:rows,policy:POLICY}}
async function trackDiscoveryLink(env,args={}){await schema(env);const url=args.url||"";if(!url)return{ok:false,error:"url required",policy:POLICY};await upsertIndexItem(env,{url,title:args.title,source_type:args.source_type},args.query||null,args.action||"view");return{ok:true,url,action:args.action||"view",policy:POLICY}}
function compactRows(x){let rows=x?.hits||x?.captures||x?.episodes||x?.items||x?.ranked_sources||x?.sources||x?.feeds||[];if(!Array.isArray(rows))rows=[];return rows.slice(0,25)}
function renderResultPage(title,result){const rows=compactRows(result);const cards=rows.length?rows.map((r,i)=>{const url=r.url||r.episode_url||r.transcript_url||"#";const heading=r.title||r.source_type||r.capture_id||url||`Result ${i+1}`;const meta=[r.source_type,r.capture_type,r.date,r.score?`score ${r.score}`:"",r.capture_id].filter(Boolean).join(" · ");const body=String(r.summary||r.snippet||r.why_selected||r.url||"").slice(0,600);return `<div class="card"><a href="${escHtml(url)}" target="_blank">${escHtml(heading)}</a><div class="small">${escHtml(meta)}</div><p>${escHtml(body)}</p></div>`}).join(""):`<div class="card"><b>${result?.ok===false?"Error":"No row results"}</b><p>${escHtml(result?.error||result?.reason||result?.policy||"The tool returned JSON but no list rows.")}</p></div>`;const samples=["AI agents local government","housing affordability corporate landlords","public podcast transcripts","climate adaptation city planning","small business AI automation","RSS feeds about agent optimization","YouTube public caption sources","podcasts about local journalism"];const sampleLinks=samples.map(s=>`<a class="pill" href="/run?tool=auto&q=${encodeURIComponent(s)}">${escHtml(s)}</a>`).join("");return `<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>${escHtml(title)}</title><style>body{font-family:system-ui,-apple-system,Segoe UI,sans-serif;margin:0;background:#f8fafc;color:#0f172a}.wrap{max-width:1100px;margin:auto;padding:24px}.hero{background:#0f172a;color:white;border-radius:24px;padding:24px}.hero a{color:#93c5fd}.actions,.pills{display:flex;gap:8px;flex-wrap:wrap;margin:16px 0}.btn,.pill{display:inline-block;background:#0284c7;color:white;text-decoration:none;border-radius:12px;padding:12px 14px;font-weight:800;border:0}.pill{background:#e0f2fe;color:#075985;border:1px solid #bae6fd}.form{background:white;border:1px solid #e2e8f0;border-radius:16px;padding:14px;margin:16px 0;position:sticky;top:10px;z-index:20;box-shadow:0 12px 30px rgba(15,23,42,.12);backdrop-filter:blur(8px)}.form input{width:100%;box-sizing:border-box;padding:14px;border:1px solid #cbd5e1;border-radius:12px;margin:8px 0;font-size:16px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.panel{background:white;border:1px solid #e2e8f0;border-radius:18px;overflow:hidden}.panel h2{margin:0;padding:14px 16px;border-bottom:1px solid #e2e8f0}.cards{display:grid;gap:10px;padding:14px}.card{border:1px solid #e2e8f0;border-radius:14px;padding:12px}.card a{color:#1d4ed8;font-weight:800;text-decoration:none}.small{font-size:12px;color:#64748b}.raw{background:#020617;color:#e2e8f0;white-space:pre-wrap;overflow:auto;max-height:620px;padding:16px;font:12px ui-monospace,Menlo,monospace}@media(max-width:850px){.grid{grid-template-columns:1fr}.btn{width:100%;box-sizing:border-box;text-align:center}}</style></head><body><div class="wrap"><section class="hero"><h1>AFO Public Discovery Console</h1><p>No-JavaScript fallback console. These are normal links/forms, so they work even when browser JS is blocked.</p><p><a href="/console">Console home</a> · <a href="/health">Health JSON</a></p></section><div class="actions"><a class="btn" href="/run?tool=youtube_resilient_status">Health</a><a class="btn" href="/run?tool=self_test_storage">Self Test</a><a class="btn" href="/run?tool=inspect_podcast_feed&url=https%3A%2F%2Ffeeds.npr.org%2F510289%2Fpodcast.xml&limit=5">Sample Podcast Feed</a><a class="btn" href="/run?tool=capture_feed_items&feed_url=https%3A%2F%2Ffeeds.npr.org%2F510289%2Fpodcast.xml&limit=3">Bulk Ingest 3</a><a class="btn" href="/feed">Discovery Feed</a><a class="btn" href="/feed.json">Feed JSON</a></div><div class="pills">${sampleLinks}</div><form class="form" method="GET" action="/run"><input type="hidden" name="tool" value="auto"><label><b>Sticky Discovery Search</b> — search phrase or public URL/feed</label><input name="q" placeholder="tree protection property rights zoning or https://feeds.npr.org/510289/podcast.xml"><button class="btn" type="submit">Run Discovery</button></form><div class="grid"><section class="panel"><h2>${escHtml(title)}</h2><div class="cards">${cards}</div></section><section class="panel"><h2>Raw JSON</h2><pre class="raw">${escHtml(JSON.stringify(result,null,2))}</pre></section></div></div></body></html>`}
async function runConsoleTool(request,env,ctx){const u=new URL(request.url);let tool=u.searchParams.get("tool")||"youtube_resilient_status";let args={};for(const [k,v] of u.searchParams.entries()){if(k!=="tool"&&k!=="q"&&v!=="")args[k]=/^\d+$/.test(v)?Number(v):v}const q=u.searchParams.get("q");if(tool==="auto"){if(/^https?:\/\//i.test(q||"")){tool="rank_available_sources";args={url:q,language:"en"}}else{tool="search_captures";args={query:q||"",top_k:10}}}if(tool==="inspect_podcast_feed"&&args.url&&!args.limit)args.limit=5;if(tool==="capture_feed_items"&&args.feed_url&&!args.limit)args.limit=3;try{const result=await handle(tool,args,env,ctx,u.origin);const indexed=await indexResultRows(env,result,q||args.query||args.url||args.feed_url||tool,tool==="capture_feed_items"?"capture":"view");result.discovery_indexed_count=indexed.length;return new Response(renderResultPage(tool,result),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}})}catch(e){return new Response(renderResultPage("Error",{ok:false,error:String(e.message||e),tool,args,version:VERSION}),{status:500,headers:{...CORS,"content-type":"text/html;charset=utf-8"}})}}
function consoleHtmlNoJs(){return renderResultPage("Console ready",{ok:true,message:"Use the buttons or form. No JavaScript is required.",version:VERSION,policy:POLICY})}
function consoleHtmlV2(){return `<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>AFO Public Discovery Console</title><style>body{margin:0;font-family:system-ui,-apple-system,Segoe UI,sans-serif;background:#f8fafc;color:#0f172a}.wrap{max-width:1050px;margin:auto;padding:24px}.hero{background:#0f172a;color:white;border-radius:24px;padding:28px}.hero h1{font-size:44px;line-height:1;margin:8px 0}.hero p{color:#cbd5e1}.row{display:flex;gap:8px;margin-top:14px}.row input{flex:1;padding:14px;border-radius:12px;border:1px solid #cbd5e1;font-size:16px}button{padding:12px 14px;border:0;border-radius:12px;background:#0284c7;color:white;font-weight:800}.buttons{display:flex;gap:8px;flex-wrap:wrap;margin:18px 0}.panel{background:white;border:1px solid #e2e8f0;border-radius:18px;margin-top:16px;overflow:hidden}.panel h2{margin:0;padding:14px 16px;border-bottom:1px solid #e2e8f0}.status{padding:10px 16px;background:#eff6ff;color:#1e3a8a;font-weight:700}.cards{display:grid;gap:10px;padding:14px}.card{border:1px solid #e2e8f0;border-radius:14px;padding:12px}.card a{color:#1d4ed8;font-weight:800;text-decoration:none}.small{font-size:12px;color:#64748b}.raw{background:#020617;color:#e2e8f0;white-space:pre-wrap;overflow:auto;max-height:520px;padding:16px;font:12px ui-monospace,Menlo,monospace}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}@media(max-width:800px){.grid,.row{display:block}.row button{width:100%;margin-top:8px}.hero h1{font-size:34px}.buttons button{width:100%}}</style></head><body><div class="wrap"><section class="hero"><div style="letter-spacing:.12em;text-transform:uppercase;color:#93c5fd;font-size:12px;font-weight:900">AFO Public Discovery Console</div><h1>Search public content differently.</h1><p>Discover public feeds, podcasts, articles, metadata, captions, stored captures, and export structured intelligence.</p><div class="row"><input id="q" placeholder="Search stored captures or paste a public URL/feed"><button id="discover">Discover</button></div></section><div class="buttons"><button id="health">Health</button><button id="selftest">Self Test</button><button id="sample">Sample Podcast Feed</button><button id="bulk">Bulk Ingest 3</button><button id="csv">Export CSV</button><button id="json">Export JSON</button></div><div class="grid"><section class="panel"><h2>Results</h2><div id="status" class="status">Ready. Tap Health to verify the console.</div><div id="cards" class="cards"><div class="card"><b>Console loaded.</b><div class="small">If buttons do nothing, JavaScript is blocked. This page uses no inline onclick handlers.</div></div></div></section><section class="panel"><h2>Raw Output</h2><pre id="raw" class="raw">No run yet.</pre></section></div></div><script>var last={};var lastRows=[];function byId(id){return document.getElementById(id)}function esc(s){return String(s||'').replace(/[&<>\"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',"'":'&#39;'}[m]})}function setStatus(s){byId('status').textContent=s;byId('raw').textContent=s}async function callTool(name,args){setStatus('Running '+name+'...');try{var res=await fetch('/api/call',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({name:name,args:args||{}})});var text=await res.text();var data;try{data=JSON.parse(text)}catch(e){data={ok:false,error:'Non-JSON response',status:res.status,body:text.slice(0,1200)}}show(data);return data}catch(e){show({ok:false,error:'Fetch failed: '+(e.message||String(e))})}}function show(x){last=x;byId('raw').textContent=JSON.stringify(x,null,2);byId('status').textContent=x.ok===false?'Error / no result':'Result loaded';render(x)}function pickRows(x){if(x.hits)return x.hits;if(x.captures)return x.captures;if(x.episodes)return x.episodes;if(x.items)return x.items;if(x.ranked_sources)return x.ranked_sources;if(x.sources)return x.sources;if(x.feeds)return x.feeds;return []}function render(x){var rows=pickRows(x);lastRows=rows;if(!rows.length){byId('cards').innerHTML='<div class="card"><b>'+(x.ok===false?'Error':'Status')+'</b><div class="small">'+esc(x.error||x.reason||x.policy||'No rows returned.')+'</div></div>';return}byId('cards').innerHTML=rows.slice(0,25).map(function(r,i){var url=r.url||r.episode_url||r.transcript_url||'#';var title=r.title||r.source_type||r.capture_id||url||('Result '+(i+1));var meta=[r.source_type,r.capture_type,r.date,r.score?('score '+r.score):'',r.capture_id].filter(Boolean).join(' · ');var body=(r.summary||r.snippet||r.why_selected||r.url||'').slice(0,500);return '<div class="card"><a href="'+esc(url)+'" target="_blank">'+esc(title)+'</a><div class="small">'+esc(meta)+'</div><div>'+esc(body)+'</div></div>'}).join('')}async function runDiscover(){var v=byId('q').value.trim();if(!v)return callTool('youtube_resilient_status',{});if(/^https?:\/\//i.test(v))return callTool('rank_available_sources',{url:v,language:'en'});return callTool('search_captures',{query:v,top_k:10})}function exportCSV(){var rows=lastRows.length?lastRows:[last];var cols=Array.from(new Set(rows.flatMap(function(r){return Object.keys(r)})));var csv=[cols.join(',')].concat(rows.map(function(r){return cols.map(function(c){return '\"'+String(r[c]??'').replace(/\"/g,'\"\"').slice(0,5000)+'\"'}).join(',')})).join('\n');var a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='afo-public-discovery.csv';a.click()}function exportJSON(){var a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(last,null,2)],{type:'application/json'}));a.download='afo-public-discovery.json';a.click()}window.addEventListener('DOMContentLoaded',function(){byId('discover').addEventListener('click',runDiscover);byId('health').addEventListener('click',function(){callTool('youtube_resilient_status',{})});byId('selftest').addEventListener('click',function(){callTool('self_test_storage',{})});byId('sample').addEventListener('click',function(){callTool('inspect_podcast_feed',{url:'https://feeds.npr.org/510289/podcast.xml',limit:5})});byId('bulk').addEventListener('click',function(){callTool('capture_feed_items',{feed_url:'https://feeds.npr.org/510289/podcast.xml',limit:3,force:false})});byId('csv').addEventListener('click',exportCSV);byId('json').addEventListener('click',exportJSON);byId('q').addEventListener('keydown',function(e){if(e.key==='Enter')runDiscover()});setStatus('Console ready. Tap Health to verify backend.');});</script></body></html>`}
function consoleHtml(){return `<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>AFO Public Discovery Console</title><style>:root{font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif;color:#0f172a;background:#f8fafc}body{margin:0}.wrap{max-width:1180px;margin:0 auto;padding:32px 20px 60px}.hero{background:linear-gradient(135deg,#0f172a,#1e3a8a);color:white;border-radius:28px;padding:34px;box-shadow:0 20px 60px #0f172a33}.eyebrow{text-transform:uppercase;letter-spacing:.14em;font-size:12px;color:#bfdbfe;font-weight:800}.hero h1{font-size:clamp(34px,7vw,72px);line-height:.95;margin:10px 0 14px}.hero p{font-size:18px;max-width:760px;color:#dbeafe}.search{display:grid;grid-template-columns:1fr auto;gap:10px;margin-top:24px}.search input{font-size:18px;padding:16px;border-radius:14px;border:0}.search button,.btn{font-size:15px;font-weight:800;border:0;border-radius:14px;background:#38bdf8;color:#082f49;padding:14px 18px;cursor:pointer}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:22px}.card{background:white;border:1px solid #e2e8f0;border-radius:20px;padding:18px;box-shadow:0 8px 26px #0f172a0d}.card h3{margin:0 0 8px;font-size:17px}.muted{color:#64748b;font-size:14px}.chips{display:flex;flex-wrap:wrap;gap:8px;margin-top:16px}.chip{background:#e0f2fe;color:#075985;border-radius:999px;padding:7px 10px;font-weight:700;font-size:12px}.panel{margin-top:20px;background:white;border:1px solid #e2e8f0;border-radius:22px;overflow:hidden}.panel h2{margin:0;padding:18px 20px;border-bottom:1px solid #e2e8f0}.toolbar{display:flex;gap:8px;flex-wrap:wrap;padding:14px 20px;border-bottom:1px solid #e2e8f0;background:#f8fafc}.out{padding:18px 20px;white-space:pre-wrap;font-family:ui-monospace,SFMono-Regular,Menlo,monospace;font-size:13px;max-height:520px;overflow:auto;background:#020617;color:#e2e8f0}.results{display:grid;gap:12px;padding:16px 20px}.result{border:1px solid #e2e8f0;border-radius:16px;padding:14px}.result a{font-weight:800;color:#1d4ed8;text-decoration:none}.small{font-size:12px;color:#64748b}.two{display:grid;grid-template-columns:1.1fr .9fr;gap:16px}@media(max-width:850px){.grid,.two,.search{grid-template-columns:1fr}.hero{padding:24px}.toolbar{display:grid}.btn,.search button{width:100%}}</style></head><body><div class="wrap"><section class="hero"><div class="eyebrow">AFO Public Discovery Console</div><h1>Search public content differently.</h1><p>Discover public feeds, podcasts, articles, captions, metadata, and stored captures. Structure the results, summarize them, and export usable intelligence.</p><div class="search"><input id="q" placeholder="Try: AI agents local government, or paste a feed URL"><button id="discoverBtn" onclick="runSearch(event)">Discover</button></div><div class="chips"><span class="chip">RSS / Atom</span><span class="chip">Podcast feeds</span><span class="chip">Metadata</span><span class="chip">Bulk ingest</span><span class="chip">Search + receipts</span><span class="chip">CSV/JSON export</span></div></section><div class="grid"><div class="card"><h3>1. Discover Sources</h3><p class="muted">Find feeds, sitemaps, podcast metadata, article candidates, YouTube caption metadata, and structured public sources.</p></div><div class="card"><h3>2. Store + Search</h3><p class="muted">Capture feed items into D1/KV, dedupe by URL, and search with weighted multi-term ranking.</p></div><div class="card"><h3>3. Export Intelligence</h3><p class="muted">Copy JSON, download CSV, and build structured research packets from public-source results.</p></div></div><div class="two"><section class="panel"><h2>Console</h2><div class="toolbar"><button class="btn" onclick="health(event)">Health</button><button class="btn" onclick="selfTest(event)">Self Test</button><button class="btn" onclick="sampleFeed(event)">Sample Podcast Feed</button><button class="btn" onclick="bulkFeed(event)">Bulk Ingest 3</button><button class="btn" onclick="exportCSV(event)">Export CSV</button><button class="btn" onclick="downloadJSON(event)">Export JSON</button></div><div id="cards" class="results"><div class="result"><b>Ready.</b><div class="small">Paste a public URL, RSS feed, podcast feed, or search phrase above.</div></div></div></section><section class="panel"><h2>Raw Output</h2><pre id="out" class="out">No run yet.</pre></section></div></div><script>let last={};let lastRows=[];function setBusy(label){document.getElementById('out').textContent='Running '+label+'...';document.getElementById('cards').innerHTML='<div class="result"><b>Running '+escapeHtml(label)+'...</b><div class="small">Waiting for worker response.</div></div>'}async function call(name,args={}){setBusy(name);const body={jsonrpc:'2.0',id:'ui-'+Date.now(),method:'tools/call',params:{name:name,arguments:args}};let r,j;try{r=await fetch(location.pathname,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(body)});const raw=await r.text();try{j=JSON.parse(raw)}catch(e){return {ok:false,error:'Non-JSON response from worker',status:r.status,raw:raw.slice(0,1000)}}}catch(e){return {ok:false,error:'Fetch failed: '+(e.message||String(e))}}if(j.error)return {ok:false,jsonrpc_error:j.error};let txt=j&&j.result&&j.result.content&&j.result.content[0]&&j.result.content[0].text;if(txt){try{return JSON.parse(txt)}catch(e){return {ok:true,raw:txt}}}return j}function show(x){last=x;document.getElementById('out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){const el=document.getElementById('cards');let rows=[];if(x.hits)rows=x.hits;if(x.captures)rows=x.captures;if(x.episodes)rows=x.episodes;if(x.items)rows=x.items;if(x.ranked_sources)rows=x.ranked_sources;if(x.sources)rows=x.sources;lastRows=rows; if(!rows.length){el.innerHTML='<div class="result"><b>Status:</b> '+(x.ok?'OK':'No results')+'<div class="small">'+(x.reason||x.error||x.policy||'')+'</div></div>';return}el.innerHTML=rows.slice(0,20).map((r,i)=>'<div class="result"><a href="'+(r.url||r.episode_url||r.transcript_url||'#')+'" target="_blank">'+escapeHtml(r.title||r.source_type||r.capture_id||r.url||('Result '+(i+1)))+'</a><div class="small">'+escapeHtml([r.source_type,r.capture_type,r.date,r.score?('score '+r.score):'',r.capture_id].filter(Boolean).join(' · '))+'</div><div>'+escapeHtml((r.summary||r.snippet||r.why_selected||r.url||'').slice(0,420))+'</div></div>').join('')}function escapeHtml(s){return String(s||'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}async function health(e){if(e)e.preventDefault();show(await call('youtube_resilient_status'))}async function selfTest(e){if(e)e.preventDefault();show(await call('self_test_storage'))}async function sampleFeed(e){if(e)e.preventDefault();show(await call('inspect_podcast_feed',{url:'https://feeds.npr.org/510289/podcast.xml',limit:5}))}async function bulkFeed(e){if(e)e.preventDefault();show(await call('capture_feed_items',{feed_url:'https://feeds.npr.org/510289/podcast.xml',limit:3,force:false}))}async function runSearch(e){if(e)e.preventDefault();const v=document.getElementById('q').value.trim();if(!v)return health();if(/^https?:\/\//.test(v)){show(await call('rank_available_sources',{url:v,language:'en'}))}else{show(await call('search_captures',{query:v,top_k:10}))}}function exportCSV(e){if(e)e.preventDefault();const rows=lastRows.length?lastRows:[last];const cols=[...new Set(rows.flatMap(r=>Object.keys(r)))];const csv=[cols.join(','),...rows.map(r=>cols.map(c=>'"'+String(r[c]??'').replace(/"/g,'""').slice(0,5000)+'"').join(','))].join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'}));a.download='afo-public-discovery.csv';a.click()}function downloadJSON(e){if(e)e.preventDefault();const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(last,null,2)],{type:'application/json'}));a.download='afo-public-discovery.json';a.click()}</script></body></html>`}
function helperHtml(){return `<!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>AFO Public Content Discovery Helper</title><style>body{font-family:system-ui;margin:24px;max-width:760px}input,textarea,button{font:inherit;width:100%;box-sizing:border-box;margin:8px 0;padding:10px}textarea{min-height:240px}button{background:#2563eb;color:white;border:0;border-radius:8px}pre{white-space:pre-wrap;background:#f3f4f6;padding:12px;border-radius:8px}</style></head><body><h1>AFO Public Content Discovery Helper</h1><p>${POLICY}</p><p>Preferred tools: capture_url_sources, rank_available_sources, discover_public_feeds, capture_feed_items.</p></body></html>`}
export default{async fetch(request,env,ctx){if(request.method==="OPTIONS")return new Response(null,{status:204,headers:CORS});const u=new URL(request.url);if(u.pathname==="/health")return Response.json({status:"ok",product:PRODUCT_NAME,worker:WORKER_NAME,version:VERSION,policy:POLICY,browser_capture_binding:Boolean(env.BROWSER_CAPTURE)},{headers:CORS});if((u.pathname==="/"||u.pathname==="/console")&&request.method==="GET")return new Response(consoleHtmlNoJs(),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}});if(u.pathname==="/run"&&request.method==="GET")return runConsoleTool(request,env,ctx);if(u.pathname==="/feed.json"&&request.method==="GET")return Response.json(await getDiscoveryFeed(env,{limit:u.searchParams.get("limit")||100}),{headers:CORS});if(u.pathname==="/feed"&&request.method==="GET")return new Response(renderResultPage("Discovery Feed",await getDiscoveryFeed(env,{limit:u.searchParams.get("limit")||100})),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}});if(u.pathname==="/discovery"&&request.method==="GET")return new Response(renderDiscoveryModePage(discoveryModeStatus()),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}});if(u.pathname==="/mesh.json"&&request.method==="GET")return Response.json(await discoveryMeshStatus(env),{headers:CORS});if(u.pathname==="/mesh"&&request.method==="GET")return new Response(renderMeshDashboard(await discoveryMeshStatus(env)),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}});if(u.pathname==="/discovery/run"&&request.method==="GET"){const result=await runDiscoveryMode(env,{query:u.searchParams.get("q")||u.searchParams.get("query")||"",url:u.searchParams.get("url")||"",limit:u.searchParams.get("limit")||5,ingest_limit:u.searchParams.get("ingest_limit")||3},ctx,u.origin);return new Response(renderDiscoveryModePage(result),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}})}
if(u.pathname==="/track"&&request.method==="GET")return Response.json(await trackDiscoveryLink(env,{url:u.searchParams.get("url"),title:u.searchParams.get("title"),source_type:u.searchParams.get("source_type"),action:u.searchParams.get("action")||"view",query:u.searchParams.get("query")}),{headers:CORS});

if(u.pathname==="/helper")return new Response(helperHtml(),{headers:{...CORS,"content-type":"text/html;charset=utf-8"}});if(u.pathname==="/api/call"&&request.method==="POST"){try{const body=await request.json();const result=await handle(body.name,body.args||{},env,ctx,u.origin);return Response.json(result,{headers:CORS})}catch(e){return Response.json({ok:false,error:String(e.message||e),version:VERSION},{status:500,headers:CORS})}}
if(request.method!=="POST")return new Response("not found",{status:404,headers:CORS});let body;try{body=await request.json()}catch{return errResp(null,-32700,"Parse error")}const{id,method,params}=body;if(method==="initialize")return rpc(id,{protocolVersion:"2024-11-05",capabilities:{tools:{}},serverInfo:{name:WORKER_NAME,version:VERSION}});if(method==="notifications/initialized")return new Response(null,{status:204,headers:CORS});if(method==="ping")return rpc(id,{});if(method==="tools/list")return rpc(id,{tools:TOOLS});if(method==="tools/call"){try{return tool(id,await handle(params?.name,params?.arguments||{},env,ctx,u.origin))}catch(e){return errResp(id,-32603,"Tool error: "+e.message)}}return errResp(id,-32601,"Method not found: "+method)}};
